// ====================== 数据动态化工具 ======================
export function seededRand(seed, min, max) {
  const x = Math.sin(seed) * 10000;
  return min + Math.floor((x - Math.floor(x)) * (max - min + 1));
}
export function getDailyBase() {
  const d = new Date();
  const seed = d.getFullYear() * 10000 + (d.getMonth()+1) * 100 + d.getDate();
  return {
    weekInteraction: seededRand(seed + 1, 10, 18),
    avgDepth:        (seededRand(seed + 2, 18, 32) / 10).toFixed(1),
    caseRate:        seededRand(seed + 3, 48, 72),
    cogScore:        ["B+","A-","A","A+"][seededRand(seed + 4, 0, 3)],
    covered:         seededRand(seed + 5, 268, 295),
    tested:          seededRand(seed + 6, 250, 280),
    interactions:    seededRand(seed + 7, 1750, 2100),
  };
}
export function jitter(base, pct) {
  const delta = Math.floor(base * pct * (Math.random() > 0.5 ? 1 : -1));
  return Math.max(0, base + delta);
}

