export function getTodayQuestion() {
  const d = new Date();
  const idx = (d.getFullYear() * 366 + d.getMonth() * 31 + d.getDate()) % DAILY_QUESTIONS.length;
  return DAILY_QUESTIONS[idx];
}

export function lv(l) { return { L: 1, M: 2, H: 3 }[l]; }
export function toLevel(s) { return s <= 4 ? "L" : s <= 6 ? "M" : "H"; }
export function shuffle(a) {
  const r = a.slice();
  for (let i = r.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1));
    [r[i], r[j]] = [r[j], r[i]];
  }
  return r;
}

